async (params, browser) => {
  // Open LinkedIn feed
  await browser.open('https://www.linkedin.com/feed/')

  // Wait for feed posts
  await browser.waitForSelector('div.feed-shared-update-v2', 15000)

  // Let feed settle
  await browser.wait(2000)

  // Scroll for more posts
  await browser.scroll({ direction: 'down', amount: 1500 })

  await browser.wait(2000)

  // Scroll more
  await browser.scroll({ direction: 'down', amount: 1500 })

  await browser.wait(2000)

  // Extract feed posts
  const feed = await browser.evaluate(`const posts = []; const containers = document.querySelectorAll('div.feed-shared-update-v2'); containers.forEach((post, i) => { if (i >= 15) return; try { const authorEl = post.querySelector('.update-components-actor__title span[dir="ltr"], .update-components-actor__title span[aria-hidden="true"]'); const authorDescEl = post.querySelector('.update-components-actor__description span[aria-hidden="true"], .update-components-actor__description'); const timeEl = post.querySelector('.update-components-actor__sub-description span[aria-hidden="true"], .update-components-actor__sub-description'); const textEl = post.querySelector('.update-components-text span[dir="ltr"], .update-components-text'); const reactionsEl = post.querySelector('.social-details-social-counts__reactions-count, .social-details-social-counts__reactions'); const commentsEl = post.querySelector('.social-details-social-counts__comments, button[aria-label*="comment"]'); const linkEl = post.querySelector('.update-components-mini-update-v2__link-to-details-page, a[href*="/feed/update/"]'); const urn = post.getAttribute('data-urn') || ''; const postId = urn.includes('activity:') ? urn.split('activity:')[1] : ''; const author = authorEl ? authorEl.textContent.trim() : ''; const text = textEl ? textEl.textContent.trim().slice(0, 500) : ''; if (!author && !text) return; posts.push({ rank: posts.length + 1, author: author, author_title: authorDescEl ? authorDescEl.textContent.trim() : '', timestamp: timeEl ? timeEl.textContent.trim() : '', text: text, reactions: reactionsEl ? reactionsEl.textContent.trim() : '0', comments: commentsEl ? commentsEl.textContent.trim().replace(/[^0-9]/g, '') || '0' : '0', post_id: postId, post_url: postId ? 'https://www.linkedin.com/feed/update/urn:li:activity:' + postId + '/' : (linkEl ? linkEl.href : '') }); } catch(e) {} }); return { count: posts.length, posts: posts }`)

  return feed
}
